mapper.select:
select cs.*,
       c.course_name,
       u.real_name as member_name,
       concat(s.week_day, ' ', s.start_section, '-', s.end_section, '节') as schedule_info
from booking_record cs
         left join repertoire_info c on cs.course_id = c.id
         left join sys_user u on cs.member_id = u.id
         left join performance_schedule s on cs.schedule_id = s.id


        and cs.schedule_id = #{scheduleId}


        and cs.member_id = #{memberId}


        and cs.select_status = #{selectStatus}


        and s.artist_id = #{artistId}


order by cs.id desc
